module top_module(
    address,
    clock,
    q
);input [11:0] address;
    input clock;
    output [11:0] q;

    reg [11:0] invalid_addr;
    wire [11:0] q_wire;

    always @(posedge clock) begin
        if (address < 12'd2048) begin
            invalid_addr <= address + 12'd100;
        end else if (address <= 12'd4095) begin
            invalid_addr <= address - 12'd100;
        end else begin
            invalid_addr <= address;
        end
    end

    assign q_wire = invalid_addr;

    assign q = q_wire;

endmodule
